INSERT INTO AUDIT_ARCHIVED_LOGS (
    ARCHIVE_ID, ORIGINAL_LOG_ID, USER_ID, ACTION, RESOURCE, DETAIL,
    IP_ADDRESS, USER_AGENT, RESULT, CREATED_AT, ARCHIVED_AT, ARCHIVED_BY, ARCHIVE_REASON
) VALUES (
    #{archiveId}, #{originalLogId}, #{userId}, #{action}, #{resource}, CAST(#{detail} AS JSON),
    #{ipAddress}, #{userAgent}, #{result}, #{createdAt}, #{archivedAt}, #{archivedBy}, #{archiveReason}
)

INSERT INTO AUDIT_ARCHIVED_LOGS (
    ARCHIVE_ID, ORIGINAL_LOG_ID, USER_ID, ACTION, RESOURCE, DETAIL,
    IP_ADDRESS, USER_AGENT, RESULT, CREATED_AT, ARCHIVED_AT, ARCHIVED_BY, ARCHIVE_REASON
) VALUES

    (
        #{log.archiveId}, #{log.originalLogId}, #{log.userId}, #{log.action}, #{log.resource},
        CAST(#{log.detail} AS JSON), #{log.ipAddress}, #{log.userAgent}, #{log.result},
        #{log.createdAt}, #{log.archivedAt}, #{log.archivedBy}, #{log.archiveReason}
    )
